// Read the ORIGINAL webhook payload by name (immediate upstream is now the
// Supersede HTTP node, whose output is the Qdrant response, not our body).
const wh = $('Webhook (POST /ingest-document)').first().json;
const body = wh.body || wh;

let text = body.text || '';
if (!text && body.content_base64) {
  text = Buffer.from(body.content_base64, 'base64').toString('utf-8');
}
if (!text || !text.trim()) {
  throw new Error('No extractable text. Provide body.text or body.content_base64.');
}

const meta = {
  document_id: body.document_id ?? null,
  doc_key: body.doc_key || body.filename || 'untitled',
  version: body.version ?? 1,
  filename: body.filename || 'untitled.txt',
  category: body.category || 'general',
  department: body.department || 'general',
  authority_weight: body.authority_weight ?? 1.0,
  source_type: body.source_type || 'text',
  effective_from: body.effective_from || null,
  effective_to: body.effective_to || null,
  uploaded_at: new Date().toISOString()
};

const chunkSize = 900;
const overlap = 100;
const chunks = [];
let start = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const index = chunks.length;
  // deterministic numeric point id from doc_key + version + index
  const s = `${meta.doc_key}_v${meta.version}_${index}`;
  let h = 0;
  for (let i = 0; i < s.length; i++) { h = ((h << 5) - h + s.charCodeAt(i)) | 0; }
  chunks.push({ ...meta, text: text.slice(start, end), chunk_index: index, point_id: Math.abs(h) });
  start += chunkSize - overlap;
}
return chunks.map(c => ({ json: c }));

